import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Select, DateRangeFilter, addToast, CatalogTableSkeleton } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { ktService } from '../../services/kt/ktService';
import type { PurchaseInvoiceDto } from '../../services/kt/models';
import { useVoucherInitData } from '../../hooks/useVoucherInitData';
import { formatDateLocal, formatVnd } from '../../utils/formatters';
import {
  formatProcessingLevelFromOptions,
  resolveProcessingLevelSelectOptions,
} from '../../utils/voucherProcessingLevelOptions';
import erp from '../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../list/ListSearchRefreshButtons';
import {
  DEFAULT_VOUCHER_LIST_PAGE_SIZE,
  VoucherListPagination,
  type VoucherListPageSize,
} from '../list/VoucherListPagination';
import { useVoucherListTableBusy } from '../list/useVoucherListTableBusy';
import { useVoucherListActions } from '../../hooks/useVoucherListActions';
import { purchaseInvoiceTestIdPrefix } from './purchaseInvoiceTestId';

const PAGE_SIZE = DEFAULT_VOUCHER_LIST_PAGE_SIZE;

export interface PurchaseInvoiceListProps {
  title: string;
  icon: string;
  invoiceType: string;
  listPath: string;
  createPath: string;
  detailPath: (id: string) => string;
}

export const PurchaseInvoiceList: React.FC<PurchaseInvoiceListProps> = ({
  title, icon, invoiceType, listPath, createPath, detailPath,
}) => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { processingLevelOptions, defaultProcessingLevel } = useVoucherInitData('purchase-invoice-list');
  const { canCreate } = useVoucherListActions('create-purchase-invoice');
  const processingLevelFilterOptions = useMemo(
    () => [
      { value: '', label: 'Tất cả mức xử lý' },
      ...resolveProcessingLevelSelectOptions(processingLevelOptions, defaultProcessingLevel),
    ],
    [processingLevelOptions, defaultProcessingLevel],
  );
  const [fromDate, setFromDate] = useState<string | undefined>();
  const [toDate, setToDate] = useState<string | undefined>();
  const [processingLevel, setProcessingLevel] = useState('');
  const [page, setPage] = useState(1);
  const [items, setItems] = useState<PurchaseInvoiceDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<VoucherListPageSize>(PAGE_SIZE);
  const testIdPrefix = purchaseInvoiceTestIdPrefix(invoiceType);
  const { showTableLoading, pulseSearch } = useVoucherListTableBusy(loading);

  const handleSearch = () => {
    pulseSearch(() => {
      setPage(1);
      setReloadKey(k => k + 1);
    });
  };
  const refresh = () => pulseSearch(() => setReloadKey(k => k + 1));

  const setPageSize = (size: number) => {
    setPageSizeState(size as VoucherListPageSize);
    setPage(1);
  };

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      ktService.getPurchaseInvoices({
        fromDate,
        toDate,
        processingLevel: processingLevel || undefined,
        invoiceType,
        page,
        pageSize,
      })
        .then(res => {
          if (cancelled) return;
          setItems(res.items);
          setTotalCount(res.totalCount);
        })
        .catch(err => { if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải danh sách', type: 'error' })); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [fromDate, toDate, processingLevel, page, pageSize, invoiceType, reloadKey, dispatch]);

  return (
    <div className={erp.page} data-testid={`${testIdPrefix}-list`}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <h1 className={erp.title}><i className={`fas ${icon}`} /> {title}</h1>
        </div>
        <div className={erp.headerActions}>
          {canCreate && (
            <Button
              variant="primary"
              data-testid={`${testIdPrefix}-create-btn`}
              onClick={() => navigate(createPath)}
            >
              <i className="fas fa-plus" /> Tạo mới
            </Button>
          )}
        </div>
      </div>
      <div className={erp.filtersBar} data-testid={`${testIdPrefix}-filters`}>
        <DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v: DateRangeValue) => { setFromDate(v.fromDate); setToDate(v.toDate); setPage(1); }} />
        <div data-testid={`${testIdPrefix}-filter-processingLevel`}>
          <Select
            value={processingLevel}
            onChange={e => { setProcessingLevel(e.target.value); setPage(1); }}
            options={processingLevelFilterOptions}
          />
        </div>
        <ListSearchRefreshButtons testIdPrefix={testIdPrefix} onSearch={handleSearch} onRefresh={refresh} />
      </div>
      <div className={erp.tableCard}>
        {showTableLoading ? (
          <CatalogTableSkeleton
            rows={Math.min(pageSize, 8)}
            data-testid={`${testIdPrefix}-table-skeleton`}
          />
        ) : items.length === 0 ? <div className={erp.empty}>Không có dữ liệu</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table} data-testid={`${testIdPrefix}-table`}>
              <thead>
                <tr>
                  <th>Số HĐ</th>
                  <th>Ngày</th>
                  <th>NCC</th>
                  <th className={erp.colRight}>Tổng tiền</th>
                  <th>Mức xử lý</th>
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.id} data-testid={`${testIdPrefix}-row-${r.id}`}>
                    <td>
                      <button type="button" className={erp.codeLink} onClick={() => navigate(detailPath(r.id))}>
                        <code>{r.code}</code>
                      </button>
                    </td>
                    <td>{formatDateLocal(r.invoiceDate)}</td>
                    <td>{r.supplierName}</td>
                    <td className={erp.colRight}>{formatVnd(r.totalAmount)}</td>
                    <td data-testid={`${testIdPrefix}-row-${r.id}-processing-level`}>
                      {formatProcessingLevelFromOptions(r.processingLevel, processingLevelOptions)}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        {!showTableLoading && (
          <VoucherListPagination
            testIdPrefix={testIdPrefix}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={setPage}
            onPageSizeChange={setPageSize}
          />
        )}
      </div>
    </div>
  );
};
